export default class EventEmitter{constructor(){this._registry={}}addListener(e,t,r){var l=allocate(this._registry,e),n={context:r,listener:t,remove(){l.delete(n)}};return l.add(n),n}emit(e){var t=this._registry[e];if(null!=t){for(var r=arguments.length,l=new Array(1<r?r-1:0),n=1;n<r;n++)l[n-1]=arguments[n];for(var i=0,s=[...t];i<s.length;i++){var a=s[i];a.listener.apply(a.context,l)}}}removeAllListeners(e){null==e?this._registry={}:delete this._registry[e]}listenerCount(e){e=this._registry[e];return null==e?0:e.size}}function allocate(e,t){var r=e[t];return null==r&&(r=new Set,e[t]=r),r}